import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { useAuth } from './context/AuthContext';
import Login from './pages/auth/Login';
import Dashboard from './pages/dashboard/Dashboard';
import Layout from './components/common/Layout';
import AdminPage from './pages/admin/AdminPage';
import AdminUsers from './pages/admin/AdminUsers';
import AdminJobTitles from './pages/admin/AdminJobTitles';
import AdminPayGrades from './pages/admin/AdminPayGrades';
import AdminWorkShifts from './pages/admin/AdminWorkShifts';
import AdminOrganization from './pages/admin/AdminOrganization';
import AdminRoles from './pages/admin/AdminRoles';
import AuditLog from './pages/audit/AuditLog';
import PimPage from './pages/pim/PimPage';
import PimEmployeeList from './pages/pim/PimEmployeeList';
import PimAddEmployee from './pages/pim/PimAddEmployee';
import PimEmployeeDetails from './pages/pim/PimEmployeeDetails';
import LeavePage from './pages/leave/LeavePage';
import LeaveTypes from './pages/leave/LeaveTypes';
import LeaveRequests from './pages/leave/LeaveRequests';
import LeaveEntitlements from './pages/leave/LeaveEntitlements';
import LeaveHolidays from './pages/leave/LeaveHolidays';
import TimePage from './pages/time/TimePage';
import TimeTimesheets from './pages/time/TimeTimesheets';
import TimeAttendance from './pages/time/TimeAttendance';
import RecruitmentPage from './pages/recruitment/RecruitmentPage';
import RecruitmentVacancies from './pages/recruitment/RecruitmentVacancies';
import RecruitmentCandidates from './pages/recruitment/RecruitmentCandidates';
import PerformancePage from './pages/performance/PerformancePage';
import PerformanceReviews from './pages/performance/PerformanceReviews';
import DirectoryView from './pages/directory/DirectoryView';
import Maintenance from './pages/maintenance/Maintenance';
import Buzz from './pages/buzz/Buzz';

const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
  return user ? children : <Navigate to="/login" />;
};

function App() {
  const { user, loading } = useAuth();
  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;

  return (
    <Routes>
      <Route path="/login" element={user ? <Navigate to="/" /> : <Login />} />
      <Route path="/" element={<ProtectedRoute><Layout /></ProtectedRoute>}>
        <Route index element={<Dashboard />} />

        <Route path="admin" element={<AdminPage />} />
        <Route path="admin/users" element={<AdminUsers />} />
        <Route path="admin/job-titles" element={<AdminJobTitles />} />
        <Route path="admin/pay-grades" element={<AdminPayGrades />} />
        <Route path="admin/work-shifts" element={<AdminWorkShifts />} />
        <Route path="admin/organization" element={<AdminOrganization />} />

        <Route path="pim" element={<PimPage />} />
        <Route path="pim/list" element={<PimEmployeeList />} />
        <Route path="pim/add" element={<PimAddEmployee />} />
        <Route path="pim/:id" element={<PimEmployeeDetails />} />

        <Route path="leave" element={<LeavePage />} />
        <Route path="leave/requests" element={<LeaveRequests />} />
        <Route path="leave/types" element={<LeaveTypes />} />
        <Route path="leave/entitlements" element={<LeaveEntitlements />} />
        <Route path="leave/holidays" element={<LeaveHolidays />} />

        <Route path="time" element={<TimePage />} />
        <Route path="time/timesheets" element={<TimeTimesheets />} />
        <Route path="time/attendance" element={<TimeAttendance />} />

        <Route path="recruitment" element={<RecruitmentPage />} />
        <Route path="recruitment/vacancies" element={<RecruitmentVacancies />} />
        <Route path="recruitment/candidates" element={<RecruitmentCandidates />} />

        <Route path="performance" element={<PerformancePage />} />
        <Route path="performance/reviews" element={<PerformanceReviews />} />

        <Route path="directory" element={<DirectoryView />} />
        <Route path="maintenance" element={<Maintenance />} />
        <Route path="buzz" element={<Buzz />} />
      </Route>
    </Routes>
  );
}

export default App;
